public interface IDataSource {
  void WriteData(string data);
  string ReadData();
}
public class FileDataSource : IDataSource {
  public void WriteData(string data) { /* write to file */ }
  public string ReadData() { /* read from file */ }
}
public class EncryptionDecorator : IDataSource {
  private readonly IDataSource _source;
  public EncryptionDecorator(IDataSource source) => _source = source;
  public void WriteData(string data) => _source.WriteData(Encrypt(data));
  public string ReadData() => Decrypt(_source.ReadData());
}

