public interface IStream {
  byte[] Read();
  void Write(byte[] data);
}
public class BufferedStream : IStream {
  private readonly IStream _inner;
  public BufferedStream(IStream inner) => _inner = inner;
  public byte[] Read() {
    // Read in chunks, buffer in memory
    return _inner.Read();
  }
  public void Write(byte[] data) {
    // Buffer writes, flush when full
    _inner.Write(data);
  }
}

