public class CachingRepository : IRepository<Product> {
  private readonly IRepository<Product> _inner;
  private readonly Dictionary<int, Product> _cache = new();

  public CachingRepository(IRepository<Product> inner) => _inner = inner;

  public Product GetById(int id) {
    if (!_cache.ContainsKey(id))
      _cache[id] = _inner.GetById(id);
    return _cache[id];
  }
}

public class LoggingDecorator : IService {
  private readonly IService _inner;
  private readonly ILogger _logger;

  public LoggingDecorator(IService inner, ILogger logger) {
    _inner = inner;
    _logger = logger;
  }

  public Result Execute(Request req) {
    _logger.Log($"Start: {req.Name}");
    var result = _inner.Execute(req);
    _logger.Log($"End: {req.Name} — {result.Status}");
    return result;
  }
}

public class Pizza {
